import json
from pathlib import Path
from collections import defaultdict

print("=" * 80)
print("CHAMPION CORPUS (outline_agent) ANALYSIS")
print("=" * 80)

path_champion = Path('/home/polaris/wt/outline_agent/data/cp4_corpus_s3gear_329.json')

if not path_champion.exists():
    print(f"File not found: {path_champion}")
else:
    with open(path_champion) as f:
        # Try reading as array first
        content = f.read()

    try:
        data = json.loads(content)
        print(f"\nType: {type(data).__name__}")

        if isinstance(data, list):
            print(f"Total rows: {len(data)}")
            if data:
                first = data[0]
                print(f"\nFirst row keys: {list(first.keys()) if isinstance(first, dict) else 'N/A'}")

                # Get sample row
                if isinstance(first, dict):
                    print(f"\nSample row:")
                    for k in list(first.keys())[:15]:
                        v = first.get(k)
                        if isinstance(v, str) and len(v) > 60:
                            print(f"  - {k}: {v[:60]}...")
                        else:
                            print(f"  - {k}: {v}")

                # Stats
                sources = set()
                tier_dist = defaultdict(int)
                claim_count = 0

                for row in data:
                    if isinstance(row, dict):
                        if 'source_url' in row:
                            sources.add(row['source_url'])
                        if 'tier' in row:
                            tier_dist[row['tier']] += 1
                        if 'claim_statement' in row or 'claim' in row:
                            claim_count += 1

                print(f"\nChampion corpus stats:")
                print(f"  - Distinct source_urls: {len(sources)}")
                print(f"  - Rows with claim: {claim_count}")
                print(f"  - Tier distribution: {dict(tier_dist)}")

        elif isinstance(data, dict):
            print(f"Total keys: {len(data)}")

    except Exception as e:
        print(f"Error parsing: {e}")

